select * from gateway_nodes

    and site_id = #{siteId}
    and region = #{region}
    and zone = #{zone}
    and status = #{status}

order by last_heartbeat_at desc nulls last
limit #{limit}

mapper.update:
update gateway_nodes
set status = 'EXPIRED', updated_at = #{now}
where lease_expires_at < #{now}
  and status not in ('EXPIRED', 'OFFLINE')
